  }

  const M = {
    es: '¡Hola ' + nombre + '! 🌿 Esperamos que lo hayas disfrutado en Oraz. Si te animas a dejarnos tu opinión en Google, nos harías un regalazo 💛\n\n👉 ' + REVIEW_URL + '\n\n¡Te esperamos pronto!',
    it: 'Ciao ' + nombre + '! 🌿 Speriamo che ti sia trovato bene da Oraz. Se ti va di lasciarci una recensione su Google, ci faresti un regalo enorme 💛\n\n👉 ' + REVIEW_URL + '\n\nA presto!',
    en: 'Hi ' + nombre + "! 🌿 We hope you enjoyed Oraz. If you'd like to leave us a Google review, it would mean the world 💛\n\n👉 " + REVIEW_URL + '\n\nSee you soon!',
    de: 'Hallo ' + nombre + '! \ud83c\\udf3f Wir hoffen, es hat dir bei Oraz gefallen. Wenn du uns auf Google eine Bewertung hinterlassen m\u00f6chtest, w\u00e4re das ein riesiges Geschenk \ud83d\\udc9b\n\n\ud83d\\udc49 ' + REVIEW_URL + '\n\nBis bald!',
  };
  const msg = M[lang] || M.es;

  try {
    await sendWhatsApp(this, to, msg);
    sentCount++;

    // Mark this reservation so we don't send again on the next cron tick.
    try {
      const newTags = [...tags, 'review_sent'];
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: SUPABASE_URL + '/rest/v1/reservations?id=eq.' + r.id,
        body: JSON.stringify({ tags: newTags }),
        headers: { 'Content-Type': 'application/json', apikey: SUPABASE_KEY, Authorization: 'Bearer ' + SUPABASE_KEY, Prefer: 'return=minimal' }
      });
    } catch(eT) { errors.push({ id: r.id, error: 'tag_update_failed: ' + (eT && eT.message ? eT.message : String(eT)) }); }
  } catch (e) {
    errors.push({ phone, error: e && e.message ? e.message : String(e) });
  }
}

return [{ json: { window: { from: sinceISO, to: untilISO }, found: reservations.length, sent: sentCount, skipped, errors } }];
